const Q_BIOLOGY_2019_MODEL_II=[{"id": "objective>Biology>2019-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a behavioural adaptation that protects prey from predators?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hibernation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shedding of leaves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secreting irritating fluid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dormancy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secreting irritating fluid is a behavioural adaptation that protects prey from predators.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2019-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The period of inactivity seen in some animals during long period of heat or drought is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aestivation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hibernation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adaptation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The period of inactivity seen in some animals during long periods of heat or drought is called aestivation. This is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. It happens during summer months.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2019-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The insect trapping movements of the leaves of the venus fly trap is a behavioural adaptation for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">support </div>", "<div style=\"font-family:Cambria;font-size:17px;\">surviving adverse weather conditions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obtaining food </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dormancy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The insect trapping movements of the leaves of the venus fly trap is a behavioural adaptation for obtaining food. The Venus flytrap is a carnivorous plant native to subtropical wetlands. It catches its prey—chiefly insects and arachnids— with a trapping structure formed by the terminal portion of each of the plant's leaves, which is triggered by tiny hairs on their inner surfaces.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2019-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Animals are said to be gregarious when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they survive adverse conditions of cold weather </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they transmit information from one individual to another </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are of the same species moving together in a group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they give an alarm to alert others to show the normal protective behaviour of the group when danger threatens </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Animals are said to be gregarious when they are of the same species moving together in a group. Gregarious behavior is a type of social behavior where individuals of the same species aggregate together. This behavior is common in insects, birds, and mammals.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2019-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of nutrition shown by spirogyra is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Symbiosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Holozoic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemosynthetic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Holophytic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Holophytic nutrition is a type of autotrophic nutrition where an organism produces its own food from inorganic substances using light or chemical energy. Spirogyra, being a green algae, uses sunlight, water and carbon dioxide to produce its own food through photosynthesis, which is a characteristic of holophytic nutrition.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2019-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The collective name for the female parts of the flower is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gynoecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">androecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stigma</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The collective name for the female parts of a flower is 'gynoecium'. The gynoecium is the group of structures that form the female reproductive organ in flowers. It is typically composed of one or more carpels. The carpel is the individual unit of the gynoecium and has a stigma, style, and ovary.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2019-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs are correctly matched with their mode of nutrition?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas – Saprophytic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium – Photosynthetic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Euglena – Mixotrophic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus – Autotrophic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Euglena is mixotrophic, meaning it can make its food through photosynthesis and also feed on organic material. Chlamydomonas is photosynthetic, not saprophytic. Paramecium is heterotrophic, and Rhizopus feeds on decaying matter (saprophytic), not autotrophic.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2019-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of nutrition in which two organisms of different species live together and derive nutrients from each other is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">symbiotic nutrition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytic nutrition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holozoic nutrition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holophytic nutrition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Symbiotic nutrition is a type of nutrition where two organisms of different species live together and derive nutrients from each other. This is a mutual relationship where both organisms benefit from each other. The other options do not describe this type of relationship. Saprophytic nutrition is where an organism feeds on dead and decaying matter, holozoic nutrition is a method of nutrition that involves the ingestion of liquid or solid organic material, digestion, absorption and assimilation of it to produce energy, and holophytic nutrition is a method of nutrition that involves photosynthesis.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2019-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement about the similarities in plant and animal transport is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Materials and hormones are transported in fluid form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The transport medium is made up of only tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their materials are transported in the same vessels </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion is not required</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In both plants and animals, materials and hormones are transported in fluid form. This is because fluids can easily flow and transport substances throughout the organism. The other options are incorrect. The transport medium is not made up of only tissues, their materials are not transported in the same vessels, and diffusion is required for the transport of substances.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2019-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes the function of lymph</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Temperature regulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Production of antibodies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Engulfing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Body defence</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of lymph is the production of antibodies. Antibodies are proteins that help fight off infections and can bind to certain harmful substances. The other options are incorrect. Lymph does not regulate temperature, it does not engulf anything, and while it does play a role in body defence, this is primarily through the production of antibodies.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2019-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major ways in which the blood is able to defend the body against disease causing organisms is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Absorption of fatty acids and glycerol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clumping </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Single circulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Translocation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The blood defends the body against disease-causing organisms through several mechanisms, one of which is clumping, also known as agglutination. This is a process where the immune system causes pathogens to stick together, making them easier to neutralize or remove. The other options do not relate to the blood's defensive mechanisms.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2019-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a transmittable character in plants </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Habit of growth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Resistance to environmental factors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Life span</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Haemophilia <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Haemophilia is a genetic disorder that impairs the body's ability to make blood clots, a process needed to stop bleeding. This is a human genetic disease and cannot be transmitted in plants. The other options are characteristics that can be transmitted in plants.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2019-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inheritable character/features possessed by an organism can be referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Genes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Locus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Traits </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Allelomorphs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inheritable characters or features possessed by an organism are referred to as traits. Traits are any characteristic or feature of an organism, such as its color, height, weight, etc. Genes are segments of DNA that carry the instructions for these traits. A locus is the specific location of a gene on a chromosome, and allelomorphs, also known as alleles, are different versions of the same gene.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2019-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the following is a process of transmission of hereditary characteristics by chromosomes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Genes relating to the same character occupy identical locations on the chromosomes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Separation of homologous chromosomes into four daughter cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Separation of gametes during fertilization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dictating the formation of a protein by a gene in a chromosome <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of transmission of hereditary characteristics by chromosomes is best described as the dictation of the formation of a protein by a gene in a chromosome. This is because genes, which are located on chromosomes, contain the instructions for the production of proteins. These proteins determine the traits or characteristics of an organism. This process is known as gene expression.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2019-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The attachment of the embryo to the wall of the uterus is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ovulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Implantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gametogenesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Placentation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The attachment of the embryo to the wall of the uterus is called implantation. After fertilization, the fertilized egg or zygote travels down the fallopian tube and into the uterus where it implants into the uterine wall. This is the beginning of pregnancy.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2019-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the reproductive system in mammals secretes a part of the seminal fluid which raises the pH of the fluid in the female reproductive system?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cowper's gland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prostate gland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vas deferens </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Seminal Vesicle</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Cowper's gland secretes the seminal fluid which raises the pH of the fluid in the female reproductive system. This alkaline fluid helps to neutralize the acidic environment of the vagina, which aids in the survival and transportation of sperm.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2019-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled <strong>a</strong> in the above diagram is used for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Detection of pressure in water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maintaining buoyancy in water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gaseous exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Movement in water </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gill cover helps the tilapia fish in gaseous exchange.  <br/> Protection: The gill cover protects the gills from damage. The gills are delicate organs that are susceptible to injury from predators, debris, and other objects in the water. The gill cover helps to protect the gills from these hazards.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>2019-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The above organism can be classified under which phylum in the animal kingdom</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nematoda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chordata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Porifera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Annelida</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tilapia fish can be classified under chordata phylum in the animal kingdom. Chordates are animals that have a notochord at some stage in their development. The notochord is a flexible rod that supports the dorsal (back) side of the body. Other chordate features include a dorsal nerve cord, pharyngeal slits, and a post-anal tail.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2019-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One important characteristics of green plant is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">possess specialized sense organs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Are usually motile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Are autotropic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Respond slowly to stimuli</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Green plants are autotrophic, meaning they can produce their own food through the process of photosynthesis. They use sunlight, carbon dioxide, and water to produce glucose, which is their food, and oxygen, which is released into the atmosphere. The other options are not universally true for all green plants.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2019-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A virus can sometimes be regarded as a living organism because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">causes diseases in plants and animals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It exists in a variety of shapes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is easily visible with the aid of an electron microscope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reproduces in living cells </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viruses can sometimes be regarded as living organisms because they reproduce in living cells. Viruses are considered 'obligate parasites' as they cannot reproduce without a host cell. They invade the host cell and use its machinery to replicate. The other options, while true, do not make a virus a living organism.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2019-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A population is best described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A group of the same species of organisms living together </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A group of animals and plants living together </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A group of insects and grasses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Different species of wild animals </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A population in biology is defined as a group of individuals of the same species living in the same area at the same time. They are capable of interbreeding and have the potential to produce fertile offspring. The other options do not accurately define a population in biological terms.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2019-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of times an organism occurs within a given area of a habitat is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Population growth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population frequency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population density</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population frequency refers to the number of times an organism occurs within a given area of a habitat. Population frequency is the proportion of individuals in a population that have a particular trait. It is calculated by dividing the number of individuals with the trait by the total number of individuals in the population.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2019-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a voluntary action?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pulling your hand away from a hot surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Taking notes during a lecture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sneezing when pepper irritates the nose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pupil contraction in bright light</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taking notes during a lecture is a voluntary action because it involves conscious thought, planning, and muscle control directed by the brain's motor cortex. The other actions—withdrawal from heat, sneezing, and pupil contraction—are involuntary reflexes or automatic responses that occur without deliberate control.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2019-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle responsible for regulating all cellular activities by housing genetic material is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nucleus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Endoplasmic reticulum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ribosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lysosome</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus controls the activities of the living cell. The nucleus is a membrane-bound organelle that contains the cell's chromosomes. It is the control center of the cell because it houses the cell's DNA, which directs the synthesis of proteins and cell division.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2019-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are components of glomerular filtrate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">All the components of blood except mineral salts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water and salt only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">All the components of blood except plasma protein and cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood cells, amino acid, salts and nitrogenous wastes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The glomerular filtrate is composed of all the components of blood except plasma proteins and cells. This is because the glomerulus, a network of capillaries in the kidney, filters the blood and allows small molecules like water, glucose, and ions to pass through while preventing larger molecules like proteins and cells from passing through.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2019-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sum total of adaptive changes from pre-existing form that have taken place over a long time resulting in diversity of forms, structures and functions among organism is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Speciation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inorganic Evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organic Evolution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organic Evolution is the sum total of adaptive changes from pre-existing form that have taken place over a long time resulting in diversity of forms, structures and functions among organisms. It involves changes in the genetic makeup of populations over time and can lead to new species.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2019-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The specific portion of a habitat which is occupied by a particular species is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ecological population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecological niche </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biotic community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecosystem</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The specific portion of a habitat which is occupied by a particular species is referred to as an 'Ecological niche'. It describes the role and position a species has in its environment; how it meets its needs for food and shelter, how it survives, and how it reproduces.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2019-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plants respiration occurs in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The stomata and lenticel only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mesophyll cells only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">All living cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The root only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is, 'All living cells'. In plants, respiration occurs in all living cells. Respiration is the process by which cells break down glucose and other organic molecules to release energy. It takes place in the mitochondria of cells, which are present in all living cells of plants. The stomata and lenticel are involved in gas exchange, but not in respiration specifically. Mesophyll cells are responsible for photosynthesis, not respiration. The root is involved in nutrient absorption, but not in respiration specifically.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2019-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of discontinuous variation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The range in height of a pea plant from 30cm to 50cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Offsprings including two male cats and three female cats </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The colour of pear plants grown in the dark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The adult body weight ranging from 50kg to 95kg</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discontinuous variation refers to the variation in characteristics that have a limited number of possible values. These characteristics are usually determined by a single gene pair. An example of this is the sex of offspring, which can only be male or female. Therefore, the option 'Offsprings including two male cats and three female cats' is an example of discontinuous variation.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2019-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following type of soil has the highest water retaining capacity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Loam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Laterite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clay </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clay soil has the highest water retaining capacity among the given options. This is due to its fine texture and small particle size, which allows it to hold water more effectively than loam, laterite, or sand. The small particles in clay soil are packed closely together, leaving little space for water to drain away, thus it retains water better.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2019-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rabbits cannot survive in an aquatic habitat because they have </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fore and hind limbs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no gills </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no fins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no scales </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rabbits cannot survive in an aquatic habitat because they do not have gills. Gills are the respiratory organ found in many aquatic organisms that extracts dissolved oxygen from water and excretes carbon dioxide. The absence of gills in rabbits means they cannot breathe in water, hence cannot survive in an aquatic habitat.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2019-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances pass through the root cell membrane by osmosis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cell sap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon dioxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water passes through the root cell membrane by osmosis. Osmosis is a type of passive transport that involves the movement of water molecules from an area of high water concentration to an area of low water concentration, across a semi-permeable membrane. In plants, water is absorbed from the soil into the root cells by osmosis.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2019-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trees in Savanna habitats usually have thick bark which mainly.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reduces the rate of transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protect them from scorching sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protect them from heavy winds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Resist bush fires</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trees in Savanna habitats usually have thick bark to resist bush fires. Savanna habitats are known for their dry climate and frequent fires. The thick bark of trees in these habitats helps to protect the inner tissues of the tree from damage during fires, allowing the tree to survive and recover after a fire.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2019-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Competition among individuals of a population increases the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Number of organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Availability of nutrient supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Survival of the fittest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enlargement of the territory</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Competition among individuals of a population increases the 'Survival of the fittest'. This is because in a competitive environment, only those individuals who are best adapted to their environment survive and reproduce. This concept is known as 'Survival of the fittest' or natural selection.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2019-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In natural selection, Darwin proposed that evolution occurred because of the following conditions except  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">that nature selects those that will survive to reproduce their kind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is a fierce competition among the offspring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">that the weaker offspring are eliminated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">food and other needs are abundant <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In natural selection, all conditions listed are proposed by Darwin except 'food and other needs are abundant'. Natural selection is based on the struggle for existence due to limited resources, not abundance. Therefore, the statement 'food and other needs are abundant' is not a part of Darwin's theory of natural selection.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2019-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances has the highest amount of energy in joules per unit weight?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbohydrates </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fats </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proteins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vitamins</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fats have the highest amount of energy in joules per unit weight. This is because fats are more energy-dense than carbohydrates and proteins. Each gram of fat provides about 9 calories of energy, while each gram of carbohydrates and proteins provides about 4 calories of energy. Vitamins do not provide energy.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2019-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of scientists discovered the Rhesus factor in human blood?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hooke and Levine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Darwin and Landsteiner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Landsteiner and Levine  <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hooke and Darwin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Rh factor in human blood was discovered by Karl Landsteiner and Alexander S. Wiener. Landsteiner and Wiener discovered the Rh factor in 1940. The Rh factor is a type of protein on the surface of red blood cells. Most people are Rh-positive. Rh-negative people do not have this protein.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2019-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The study of an individual organism or a single species of organism and its environment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Autecology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecological concepts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Synecology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biotic composers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The study of an individual organism or a single species of organism and its environment is known as Autecology. Autecology is a sub-field of ecology that deals with the ecological study of individual species in relation to the environment. It focuses on how the individual organism's physiology, behavior, and life history traits respond to environmental conditions.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2019-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a nitrifying bacterium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rhizobium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mycobacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Azotobacter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrosomonas</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrosomonas is a nitrifying bacterium. Nitrifying bacteria are chemolithotrophic organisms that include species of the genera Nitrosomonas, Nitrosococcus, Nitrobacter and Nitrococcus. These bacteria get their energy by the oxidation of inorganic nitrogen compounds. Nitrosomonas oxidizes ammonia into nitrite as a metabolic process.</div>", "topic": "ECOLOGY : NUTRIENT CYCLING IN NATURE"}, {"id": "objective>Biology>2019-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the effect of using artificial pollination in plant breeding?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Production of healthy crops </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lengthening the maturity time of crops </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Making crops susceptible to disease </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Improvement of the variety of crops </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Artificial pollination in plant breeding is primarily used to improve the variety of crops. It allows for the combination of desirable traits from different plants to create a new variety with improved characteristics. This can include traits such as disease resistance, yield, and quality. Therefore, the correct answer is 'Improvement of the variety of crops'.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}];
